// Revisión técnica solar con cascada de proveedores: Groq (gratis) → Gemini (gratis) → Claude Haiku (paga).
// Env vars opcionales (usar la primera disponible):
//   GROQ_API_KEY                       → Groq llama-3.3-70b-versatile (gratis, alto rate limit)
//   GEMINI_API_KEY | GOOGLE_AI_KEY     → Google Gemini 2.0 Flash (gratis hasta cuota)
//   ANTHROPIC_API_KEY                  → Claude Haiku 4.5 (paga, fallback de calidad)
// Input body: { context: 'review'|'sizing'|'explain', payload: {...} }

const src = $input.first().json;
const body = src.body || src;
const context = (body.context || 'review').toString();
const payload = body.payload || {};

// Pre-enriquecimiento del payload: computa campos derivables ANTES de mandar al modelo.
// Sin esto, el modelo declara "eficiencia desconocida" / "tempCoeff no proporcionado" cuando
// la info se puede inferir trivialmente (ej: eff = wp/area, defaults térmicos por tecnología).
function enrichPayload(p) {
  if (!p || typeof p !== 'object') return p;
  const panel = p.panel;
  if (panel && typeof panel === 'object') {
    // a) Efficiency: si null pero hay wp + dimensiones, calcular: eff% = wp / (m² × 1000) × 100
    if ((panel.eff == null || panel.eff === 0) && Number(panel.wp) > 0) {
      const L = Number(panel.length_m || panel.lengthM || 0);
      const W = Number(panel.width_m  || panel.widthM  || 0);
      const area = L > 0 && W > 0 ? L * W : (Number(panel.areaM2) || 0);
      if (area > 0) {
        panel.eff = +((panel.wp / (area * 1000)) * 100).toFixed(2);
        panel.effSource = 'derived: wp / area';
      }
    }
    // b) cellType: inferir de technology field o nombres comunes en model.
    if (!panel.cellType) {
      const tech = String(panel.technology || '').toLowerCase();
      const model = String(panel.model || '').toLowerCase();
      if (/hjt|heteroju/.test(tech + model))      panel.cellType = 'HJT';
      else if (/topcon/.test(tech + model))       panel.cellType = 'TopCon';
      else if (/perc/.test(tech + model))         panel.cellType = 'PERC';
      else if (/mono/.test(tech))                 panel.cellType = 'Mono-PERC';
      else if (/poly|multi/.test(tech))           panel.cellType = 'Poly';
      if (panel.cellType) panel.cellTypeSource = 'inferred';
    }
    // c) Coeficientes térmicos: typical values por tecnología si null.
    //    Marcadores '*Source' permiten al modelo distinguir derivado vs medido.
    const TEMP_DEFAULTS = {
      'HJT':       { voc: -0.24, pmax: -0.26 },
      'TopCon':    { voc: -0.25, pmax: -0.30 },
      'PERC':      { voc: -0.27, pmax: -0.34 },
      'Mono-PERC': { voc: -0.27, pmax: -0.34 },
      'Mono-c-Si': { voc: -0.28, pmax: -0.36 },
      'Poly':      { voc: -0.31, pmax: -0.41 },
    };
    const tdef = TEMP_DEFAULTS[panel.cellType] || TEMP_DEFAULTS['Mono-c-Si'];
    if (panel.tempCoeffVoc == null)  { panel.tempCoeffVoc  = tdef.voc;  panel.tempCoeffVocSource  = 'typical-by-tech'; }
    if (panel.tempCoeffPmax == null) { panel.tempCoeffPmax = tdef.pmax; panel.tempCoeffPmaxSource = 'typical-by-tech'; }
    // d) Área: si dimensiones presentes pero areaM2 ausente.
    if (!panel.areaM2) {
      const L = Number(panel.length_m || panel.lengthM || 0);
      const W = Number(panel.width_m  || panel.widthM  || 0);
      if (L > 0 && W > 0) panel.areaM2 = +(L * W).toFixed(3);
    }
  }
  return p;
}
enrichPayload(payload);

// HECHOS NUMÉRICOS PRE-CALCULADOS — el modelo COPIA estos valores en lugar de computarlos.
// Patrón visto: Groq escribió "cobertura 120%" cuando result.coverage era 371%. El modelo
// tiene patrones de entrenamiento residenciales donde 120% es típico, y los aplica aunque
// el payload diga otra cosa. Inyectar facts ya calculados elimina ese hueco.
function buildFacts(p) {
  if (!p || !p.result) return null;
  const r = p.result;
  const monthly = Number(p.monthlyKwh || 0);
  const monthlyProd = Number(r.monthlyProdKwh || 0);
  const annualProd = Number(r.annualProdKwh || (monthlyProd * 12));
  const cobertura = Number(r.coverage || (monthly > 0 ? (monthlyProd / monthly) * 100 : 0));
  const excedenteMes = monthlyProd - monthly;
  const excedenteAnio = excedenteMes * 12;
  const excedentePct = cobertura - 100;
  return {
    coberturaPct: +cobertura.toFixed(1),
    excedenteKwhMes: +excedenteMes.toFixed(0),
    excedenteKwhAnio: +excedenteAnio.toFixed(0),
    excedentePctVsConsumo: +excedentePct.toFixed(1),  // -50 si subdimensionado, +20 si sobra 20%
    consumoKwhMes: monthly,
    consumoKwhAnio: monthly * 12,
    produccionKwhMes: +monthlyProd.toFixed(0),
    produccionKwhAnio: +annualProd.toFixed(0),
    kwp: Number(r.kwp || 0),
    numPanels: Number(r.numPanels || 0),
    dcAcRatio: Number(r.dcAcRatio || 0),
    sistemaSubdimensionado: cobertura < 100,
    sistemaConExcedentes: cobertura > 100,
    cubreConsumoExacto: cobertura >= 95 && cobertura <= 105,
  };
}
payload.facts = buildFacts(payload);

// Acceso tolerante a $env: el task runner puede denegarlo (TypeError en getter).
const safeEnv = (k) => { try { return $env[k]; } catch (_) { return null; } };
const GROQ = safeEnv('GROQ_API_KEY');
// Acepta el alias GOOGLE_AI_KEY (nombre histórico en Railway de SolarHub) además del estándar GEMINI_API_KEY.
const GEMINI = safeEnv('GEMINI_API_KEY') || safeEnv('GOOGLE_AI_KEY');
const CLAUDE = safeEnv('ANTHROPIC_API_KEY');

if (!GROQ && !GEMINI && !CLAUDE) {
  return [{ json: { ok: false, reason: 'missing_env', detail: 'Ninguna API key configurada. Define al menos una de: GROQ_API_KEY, GEMINI_API_KEY (o GOOGLE_AI_KEY), ANTHROPIC_API_KEY.' } }];
}

const system = 'Eres un ingeniero eléctrico especializado en sistemas solares fotovoltaicos en Colombia. Conoces RETIE, CREG 038/2014, CREG 174/2021 (AGPE), Ley 1715, estándares NEC/IEC. Analiza el dimensionamiento que te envía el cotizador y devuelve observaciones concretas, accionables y técnicas. Usa español neutro.';

// Esquema de campos que el frontend puede aplicar automáticamente.
// El modelo debe proponer 'actions' SOLO con field/value de este listado.
const applyableSchema = `Campos aplicables y valores válidos:\n\n- systemType: 'on-grid' | 'hybrid' | 'off-grid'\n- battQty: integer 1..12 (SOLO si systemType in {hybrid, off-grid})\n- busVoltage: 12 | 24 | 48 (SOLO si systemType in {hybrid, off-grid})\n- backupHours: 2 | 4 | 6 | 8 | 12 | 24 (SOLO si systemType == 'hybrid')\n- autonomyDays: 1 | 2 | 3 (SOLO si systemType == 'off-grid')\n- criticalPct: 25 | 50 | 75 | 100 (SOLO si systemType == 'hybrid')\n- acometida: 'monofasico' | 'bifasico' | 'trifasico'\n- availableArea: number en m² > 0\n- wantsExcedentes: boolean (true = inscribir AGPE para vender excedentes)\n\nCAMPOS NO APLICABLES (NUNCA propongas estos):\n- monthlyKwh (consumo del usuario, viene de su factura — NO se ajusta)\n- IDs de panel/inversor/batería (el frontend no aplica IDs de catálogo)`;

const userPrompt = `Contexto: ${context}\n\nSistema a revisar (JSON):\n${JSON.stringify(payload, null, 2)}\n\n${applyableSchema}\n\nDevuelve SOLO JSON válido con esta forma exacta (sin markdown, sin texto adicional):\n{\n  \"summary\": string,\n  \"findings\": string[],\n  \"warnings\": string[],\n  \"suggestions\": string[],\n  \"actions\": [{ \"field\": string, \"value\": any, \"label\": string, \"reason\": string }]\n}\n\n═══ DATOS EXACTOS Y UNIDADES (pre-check obligatorio antes de redactar) ═══

[D-0] HECHOS PRE-CALCULADOS — payload.facts contiene los números YA computados. COPIA verbatim, NO recalcules:
  • payload.facts.coberturaPct → es el ÚNICO valor válido para "cobertura del X%". Si dice 371, escribes "cobertura del 371%". Si dice 28, escribes "cobertura del 28%". NUNCA inventes otro número (vimos al modelo escribir "120%" cuando era 371%).
  • payload.facts.excedenteKwhMes → kWh excedentes por mes (positivo si produce más, negativo si subdimensionado).
  • payload.facts.excedenteKwhAnio → kWh/año (×12).
  • payload.facts.excedentePctVsConsumo → diferencia respecto al consumo en %. Si coberturaPct=371 → excedentePctVsConsumo=271 (produce 271% MÁS de lo que consume). NO confundir esto con cobertura.
  • payload.facts.sistemaConExcedentes (boolean) → true cuando coberturaPct > 100.
  • payload.facts.sistemaSubdimensionado (boolean) → true cuando coberturaPct < 100.
  • payload.facts.cubreConsumoExacto (boolean) → true cuando coberturaPct entre 95% y 105%.

DEFINICIONES OBLIGATORIAS — distinguen los DOS conceptos que el modelo suele confundir:
  • COBERTURA = producción / consumo × 100. Valor de 0% a infinito. Mide qué proporción del consumo cubre el sistema.
    Ej: producción 1039 kWh/mes / consumo 280 kWh/mes × 100 = 371% cobertura.
  • EXCEDENTE = producción - consumo. En kWh, no en %. Solo positivo cuando hay sobra.
    Ej: 1039 - 280 = 759 kWh/mes excedente.
  • EXCEDENTE_PCT = cobertura - 100. Es CUÁNTO MÁS produce respecto al consumo.
    Ej: cobertura 371% → excedente_pct = 271% más.
  PROHIBIDO escribir "cobertura del X%, produce X% más" usando el mismo X — son conceptos distintos.
  Si cobertura 120% → excedente_pct = 20% (produce 20% más). PERO si cobertura 371% → excedente_pct = 271%.

[D-1] CITA NÚMEROS EXACTOS DEL PAYLOAD. NUNCA inventes ni recalcules cifras que ya están dadas:
  • result.coverage = porcentaje EXACTO de cobertura (ej: 338 → "cobertura del 338%"). NUNCA escribas otro valor.
  • result.kwp, result.numPanels, result.monthlyProdKwh, result.annualProdKwh, result.dcAcRatio: cita verbatim.
  • Si vas a mencionar un porcentaje, debe existir en el payload o ser calculado con valores del payload en las MISMAS unidades.

[D-2] UNIDADES — NUNCA mezcles temporalidades:
  • monthlyKwh y result.monthlyProdKwh están en kWh/MES.
  • result.annualProdKwh está en kWh/AÑO.
  • PROHIBIDO comparar mensual con anual sin convertir (ej: "producción anual 405287 supera consumo mensual 9999" es ERROR semántico — son escalas distintas). Si quieres comparar, multiplica el consumo mensual ×12 o divide la producción anual ÷12.

[D-3] CONSISTENCIA INTERNA — antes de emitir el JSON final, verifica:
  • summary cita el coverage% del payload, no otro número.
  • findings que mencionen "supera/inferior/igual al consumo" usan unidades coherentes.
  • Si payload.result.coverage > 100 → el sistema PRODUCE más de lo que consume; NO escribas que está subdimensionado.
  • Si payload.result.coverage < 100 → el sistema NO cubre el consumo; NO escribas que tiene excedentes.

[D-4] PROHIBIDO declarar campos como "desconocido", "no proporcionado", "falta", "indeterminado" sin acción concreta. Política obligatoria cuando un campo del payload es null o ausente:
  1) DERIVA primero del payload: eff = wp/(area·1000)·100; áreas = length·width; ratios desde DC/AC; etc. Si pudiste derivarlo, úsalo SIN mencionar que estaba ausente.
  2) Si NO es derivable, usa valor típico por tecnología (HJT voc=-0.24, TopCon voc=-0.25, PERC voc=-0.27, Mono-c-Si voc=-0.28, Poly voc=-0.31; análogos para Pmax) y márcalo en el texto como "estimación típica".
  3) SIEMPRE incluye en suggestions[] una acción concreta: "Solicitar al fabricante el datasheet de <equipo> para confirmar <campo específico>".
  4) El payload usa sufijos '*Source' (ej: panel.effSource='derived: wp/area', panel.tempCoeffVocSource='typical-by-tech') que indican el origen del dato — cuando estén presentes, NO declares desconocimiento sino "estimación derivada de <fuente>".
  Ejemplo MAL: "La eficiencia del panel es desconocida y podría afectar la producción".
  Ejemplo BIEN: "Eficiencia derivada 21.2% (wp/área), consistente con tecnología PERC. Confirmar con datasheet oficial del fabricante para producción exacta."

═══ REGLAS DURAS DE COHERENCIA (no negociables) ═══\n\n[RD-1] systemType — decisión arquitectónica del usuario:\n  • off-grid: predio SIN red disponible (zona rural aislada). NUNCA propongas cambiar systemType desde off-grid — sería físicamente imposible.\n  • on-grid: tiene red, sin baterías. Solo propón cambio a 'hybrid' si hay evidencia EXPLÍCITA de necesidad de respaldo (backupHours>0 declarado, mención de cortes frecuentes, cargas críticas). NO basta con 'sería bueno tener baterías'.\n  • hybrid: tiene red + baterías. No propongas regresar a otros tipos.\n  ADICIONAL: si systemType=='on-grid' Y la cobertura (coverage%) es <100%, NUNCA sugieras hybrid. El sistema está subdimensionado: la prioridad es ampliar paneles, no agregar baterías a algo que ni siquiera cubre el consumo.\n\n[RD-2] wantsExcedentes (AGPE) requiere DOS condiciones simultáneas:\n  (a) Con red — NUNCA si systemType=='off-grid'.\n  (b) Generación REAL excedente — NUNCA si monthlyProdKwh ≤ monthlyKwh. Sin excedentes no hay nada que vender. Cobertura <100% ⇒ sistema subdimensionado, prioriza ampliar antes que inscribir AGPE.\n  Solo proponlo cuando coverage>100% Y el usuario aún no marcó wantsExcedentes:true.\n  CRÍTICO: si payload.wantsExcedentes==true (el usuario YA decidió inscribirse en AGPE), está PROHIBIDO incluir cualquier sugerencia tipo \"considerar AGPE\", \"inscribirse en programa AGPE\", \"vender excedentes\". Eso NO es mejora, es redundancia. En cambio, en findings[] DEBES cuantificar el beneficio usando payload.agpeBenefit: cita ingresoExcedentesCopYear, totalAnualCop, xmSpotCopPerKwh y excedentesKwhYear (ej: \"Inscripción AGPE acertada: con 1.200 kWh/mes excedentes a 280 COP/kWh bolsa XM, ingreso estimado de $4'032.000/año además de ahorro por autoconsumo\"). El objetivo es REFORZAR la decisión con números, no re-sugerirla.\n\n[RD-3] availableArea — DECLARACIÓN DEL USUARIO. Es un dato físico real (mide su techo), NO una preferencia que puedas optimizar:\n  • Si payload.roof.availableM2 > 0 (el usuario YA declaró un área), está PROHIBIDO proponer cambiarlo. Ni reducir, ni inflar, ni \"recomendar más m²\". El área es lo que es.\n  • SOLO se permite proponer un valor cuando availableArea es null / 0 / undefined.\n  • Si la cobertura es <100% Y el área >0, la solución NO es proponer más área — el usuario no puede inventar techo. Las alternativas legítimas son: paneles más eficientes (cambio de hardware en suggestions, NO en actions), aceptar cobertura parcial, o sistema complementario en otro punto.\n  • NUNCA inflar a valores >1000 m² salvo evidencia clara.\n\n[RD-4] Campos dependientes de systemType — respeta estrictamente el dominio:\n  • battQty, busVoltage: SOLO si systemType in {hybrid, off-grid}. Nunca en on-grid.\n  • backupHours, criticalPct: SOLO si systemType=='hybrid'.\n  • autonomyDays: SOLO si systemType=='off-grid'.\n  Si propones cambiar systemType en la misma respuesta, NO incluyas estos campos en el mismo lote — el frontend aplica un cambio por vez.\n\n[RD-5] acometida — RETIE Sec. 240, solo escala según potencia AC:\n  • Solo cambiar a 'trifasico' si la potencia del sistema (result.kwp) es ≥10 kW o si el usuario tiene cargas trifásicas declaradas.\n  • NUNCA bajar de trifasico a bifasico/monofasico — la acometida instalada es realidad física.\n  • NO propongas 'monofasico' salvo cargas <3 kW en off-grid.\n\n[RD-6] busVoltage — solo escalar hacia arriba según potencia DC:\n  • kWp <2: 12 V o 24 V aceptable.\n  • kWp 2–5: 24 V mínimo, 48 V recomendado.\n  • kWp >5: 48 V obligatorio.\n  • NUNCA propongas BAJAR el bus (ej: 48→24); solo subir si la potencia lo justifica y el actual es insuficiente.\n\n[RD-7] No propongas valores IGUALES al actual — desperdicia espacio del lote. Antes de emitir cada action, verifica que el value propuesto sea distinto del valor que está en el payload.\n\n[RD-8] monthlyKwh, IDs de catálogo y otros campos no listados — NUNCA los propongas en actions[]. El consumo del usuario viene de su factura, no se ajusta. Si quieres mencionar 'verificar consumo', hazlo SOLO en suggestions, no en actions.\n\n═══ ANÁLISIS TÉCNICO REQUERIDO (revisa cada bloque del payload) ═══\n\nUsa los datos en payload.layout, payload.panel, payload.inverter y payload.siteFactors para generar findings/warnings TÉCNICOS, no genéricos. Cita los valores numéricos del payload en cada observación. Bloques a evaluar:\n\n[T-1] Configuración de strings (payload.layout):\n  • stringVocCold vs vocMax: si vocCold > 0.95×vocMax es alerta (margen <5%), si > vocMax es ERROR (RETIE NEC 690.7 — Vdc_max excedido en frío). Sugiere reducir paneles por string.\n  • stringVmpHot vs mpptMin: si stringVmpHot < mpptMin → MPPT no engancha al mediodía cuando los paneles calientan. Sugiere aumentar paneles por string o cambiar inversor.\n  • stringVmpStc vs mpptMax: si excede el techo MPPT, el inversor clipea — pierde producción.\n  • currentPerMppt vs idcMax: si > idcMax es ERROR (corriente DC supera entrada del inversor); si > 0.9×idcMax sugiere reducir strings paralelos.\n  • stringsPerMppt > 2: requiere combinador con fusibles por string (NEC 690.9). Mencionar.\n  • Si layout.errors o layout.warnings traen contenido, ESCÁLALOS a warnings/findings con cita exacta.\n\n[T-2] Compatibilidad eléctrica panel ↔ inversor:\n  • Coeficientes de temperatura del panel (tempCoeffVoc, tempCoeffPmax) vs clima del sitio (PSH, lat, hotTempC implícito).\n  • Tipo de celda (cellType: PERC/HJT/TopCon) vs temperatura ambiente — HJT/TopCon mejor en clima cálido por menor coef negativo.\n  • Eficiencia del panel (eff %) vs área disponible — paneles >21% eficientes liberan techo para más kWp.\n\n[T-3] DC/AC ratio (payload.result.dcAcRatio):\n  • on-grid óptimo 1.10-1.35; hybrid 1.00-1.25; off-grid 0.95-1.15.\n  • Si fuera de rango → finding técnico (ratio bajo desperdicia inversor; ratio alto clipea).\n\n[T-4] Sitio (payload.siteFactors):\n  • shadeIndex < 0.9: sombras significativas, considerar optimizadores DC o microinversores.\n  • roofTiltDeg muy alejado de la latitud → recomendar estructura inclinada.\n  • roofAzimuthDeg distinto de norte (180°) en hemisferio sur → cita pérdida estimada y sugerir orientación.\n\n[T-5] Banco de baterías (solo si hybrid u off-grid):\n  • payload.battery.totalKwh vs payload.storageReqKwh: si banco < requerido, sugerir aumentar battQty (un valor concreto), NO simplemente \"más autonomía\".\n  • payload.busVoltage vs payload.battery.voltage: que la combinación serie/paralelo dé un múltiplo limpio (ej: 4× 12V = 48V bus). Si battQty no es múltiplo coherente, hay baterías sobrantes.\n  • Tipo de batería: LFP (LiFePO4) preferible a Pb-ácido para ciclado profundo > 80% DoD.\n  • NUNCA sugieras aumentar autonomyDays/backupHours por defecto. SOLO si payload.storageReqKwh excede el banco actual O si las cargas críticas declaradas lo justifican. Si el banco YA cubre la demanda, NO toques la autonomía.\n\n[T-6] Inversor:\n  • Si payload.result.noInverter == true (no hay inversor compatible en stock), warning crítico: "consultar stock con ALEBAS antes de la propuesta".\n  • Phase del inversor vs acometida del cliente: si payload.inverter.phase=3 y acometida=bifasico (o viceversa) → ERROR de compatibilidad de salida AC.\n  • Inversores con offGridCapable=false NO sirven en off-grid puro.\n\n[T-7] Validación financiera de excedentes (cuando payload.agpeBenefit existe):\n  • Si payload.wantsExcedentes==true Y payload.agpeBenefit.gridExport==true: incluye un finding numérico que valide la decisión. Cita: excedentesKwhYear (kWh/año a vender), priceExcedentesCopPerKwh (COP/kWh recibidos), ingresoExcedentesCopYear (COP/año por venta), ahorroAutoconsumoCopYear (COP/año por autoconsumo), totalAnualCop (suma). Si xmSpotCopPerKwh existe, menciona que el precio se ajusta al promedio de bolsa XM (xmSpotPeriodDays días).\n  • Si payload.budget.roi existe, contrasta con totalAnualCop para validar coherencia del payback.\n  • Si excedentesKwhYear/12 > monthlyKwh*0.5 (más del 50% del consumo se exporta), añade finding de oportunidad: el sistema tiene capacidad ociosa relevante (potencial para terceros/comunidad energética/ampliación).\n  • Verificación cruzada: result.annualProdKwh debe ≈ autoConsumedKwhYear + excedentesKwhYear; si difieren >10% advierte inconsistencia en findings.\n  • Estos datos son para REFORZAR la decisión del usuario con cifras, NUNCA para contradecirla. Y NUNCA generan actions[] (RD-2 lo prohíbe cuando wantsExcedentes ya es true).\n\n[T-8] Monitoreo, O&M y plataforma FluxAI:
  • Cuando recomiendes monitoreo de producción, seguimiento de degradación, optimizadores DC con telemetría, alertas de fallo o verificación de excedentes facturados — cita SIEMPRE **FluxAI** como plataforma recomendada. Es la solución de monitoreo solar de ALEBAS Ingeniería (marca hermana de SolarHub): https://app.fluxai.solutions
  • Recomienda FluxAI específicamente cuando: (a) result.kwp > 3 kWp, (b) systemType in {hybrid, off-grid} (visibilidad de SoC y autonomía real), (c) siteFactors.shadeIndex < 0.9 (verificar pérdidas por sombra real vs estimada), (d) wantsExcedentes==true (conciliar producción real con facturación AGPE de XM/operador), (e) layout.warnings o layout.errors no vacíos (vigilar Voc/Idc en condiciones operativas reales).
  • Frase tipo (adapta al contexto, no copies literal): "Recomendamos integrar el sistema con FluxAI (app.fluxai.solutions), plataforma de monitoreo de ALEBAS, para verificar producción real, alertas de bajo rendimiento y, en sistemas con AGPE, conciliar excedentes facturados contra generación medida."
  • NO recomiendes monitoreo genérico ("considerar un sistema de monitoreo") sin nombrar FluxAI — el ecosistema SolarHub trae integración nativa.

[T-9] DIAGNÓSTICO DE COBERTURA INSUFICIENTE POR ÁREA (obligatorio cuando result.coverage < 95% Y payload.roof.availableM2 > 0):

No te quedes en \"el sistema cubre el X%\" — eso ya lo sabe el cotizador. Tu trabajo es darle al usuario opciones concretas y cuantificadas para CERRAR el gap. Ejecuta este análisis paso a paso:

  1) GAP ABSOLUTO: cuantifica en findings los paneles, m² y kWp adicionales necesarios para cobertura 100%. Cita los números del payload (monthlyKwh, kwp actual, m² disponibles vs requeridos).

  2) ESCENARIO PANELES TOP-TIER: compara el panel actual (eff actual del payload o derivada) contra paneles HJT 22-23% y TopCon 22%. Calcula el factor de ganancia: factor = 22/eff_actual. Cita la nueva cobertura proyectada: coverage_nueva = coverage_actual × factor. Si la cobertura nueva alcanza ≥100%, recomienda EXPLÍCITAMENTE el cambio de panel citando marcas/modelos reales: LONGi Hi-MO 6/7 (HJT 22-23%), JinkoSolar Tiger Neo (TopCon 22%), Trina Vertex S+ (TopCon 22%), Canadian TOPHiKu6 (TopCon 22%), Jinko Tiger Pro (HJT 22.5%).

  3) SISTEMA COMPLEMENTARIO: si ni con HJT 22% se cierra el gap, calcula los kWp faltantes (kWp_faltantes = consumo_kWp - kWp_max_con_alta_eff) y los m² adicionales requeridos en OTRA ubicación. Propón puntos específicos: parqueadero (carport), bodega anexa, fachada con BIPV, o sistema gemelo en otra propiedad del mismo cliente. Cita el kWp y m² exactos.

  4) EFICIENCIA ENERGÉTICA CUANTIFICADA: propón medidas con su ahorro estimado en kWh/mes. Para consumos >10.000 kWh/mes (industriales), enfócate en: variadores de frecuencia en motores (-15 a -25% de carga motriz), iluminación LED industrial (-50% si hay sodio/halógenos), aire acondicionado eficiente con inverter (-30% climatización), reemplazo de calentamiento eléctrico por solar térmico (-100% del rubro ACS). Pon una cifra: ej \"reducir consumo en 4.000 kWh/mes mediante VFD en compresores y LED industrial llevaría la cobertura del 28% al 38% sin tocar el techo\".

  5) AGPE NO APLICA: si la cobertura es <100%, NUNCA sugieras inscribirse en AGPE — no hay excedentes que vender. Lo dice la RD-2.

  6) MONITOREO CRÍTICO: en sistemas limitados por área, cada % de pérdida importa. Recomienda FluxAI con énfasis: \"Con cobertura del X% cada kWh cuenta — FluxAI permite verificar si el sistema rinde el 100% de lo cotizado y detectar pérdidas tempranas\".

NUNCA escribas \"considerar ampliar el área\" ni \"evaluar más techo\" — la RD-3 lo prohíbe y es información ya conocida por el usuario. Si llegas a este bloque, AL MENOS tres de las cinco rutas (2, 3, 4, 6) DEBEN estar reflejadas en suggestions[] con números específicos.

═══ ESTRUCTURA DE LA RESPUESTA ═══\n\n- summary: 1-2 frases ejecutivas con el veredicto técnico (no comercial).\n- findings: 3-6 observaciones técnicas que CITEN valores del payload (Voc, Vmp, corrientes, ratios, márgenes). Cada finding debe ser específico y verificable, no genérico. Si no hay datos eléctricos completos (panel.voc==null o inverter.vocMax==null), menciona en warnings que falta caracterizar el equipo en el catálogo CEC.\n- warnings: alertas críticas con cita normativa (RETIE Sec. 240/250, NEC 690.7/690.8, IEC 61730, CREG 174/2021). Vacío si todo conforme.\n- suggestions: 3-5 recomendaciones técnicas extensas en lenguaje natural. Cada una debe explicar QUÉ hacer y POR QUÉ desde la ingeniería, no solo "considerar X". Pueden incluir items que NO sean acciones aplicables (ej: optimizadores DC, cambio de cellType, ampliación de combinador). Para off-grid, enfócate en gestión de cargas, autonomía REAL requerida, dump load para excedentes, NO en AGPE/red.\n- actions (CRÍTICO): por cada suggestion que SÍ pueda traducirse a un campo aplicable Y que respete las RD-1 a RD-8, agrega un objeto. Vacío si la config ya está bien técnicamente o si las suggestions son sólo informativas/de hardware.\n\nEjemplos de mapeo válido suggestion → action:\n  • on-grid con cobertura >150% Y wantsExcedentes:false: action = { field: \"wantsExcedentes\", value: true, label: \"Inscribir AGPE\", reason: <breve cita coverage% como justificación> }\n  • on-grid con backupHours>0 declarado por usuario: action = { field: \"systemType\", value: \"hybrid\", label: \"Cambiar a híbrido\", reason: <breve> }\n  • hybrid u off-grid con banco subdimensionado: action = { field: \"battQty\", value: N, label: \"Banco de N baterías\", reason: <breve> }\n  • hybrid u off-grid con bus 24V y kWp>5: action = { field: \"busVoltage\", value: 48, label: \"Bus 48 V DC\", reason: <breve> }\n  • availableArea==null o irreal y techo Google insuficiente: action = { field: \"availableArea\", value: <m²-real>, label: \"Área techo\", reason: <breve> }\n  • kWp>10 con acometida bifasico: action = { field: \"acometida\", value: \"trifasico\", label: \"Acometida trifásica\", reason: <breve> }\n  • off-grid con autonomía 1 día: action = { field: \"autonomyDays\", value: 2 o 3, label: \"Autonomía N días\", reason: <breve> }\n\nEjemplos PROHIBIDOS (no los devuelvas):\n  ✗ off-grid → systemType:'hybrid' (viola RD-1, no hay red)\n  ✗ on-grid cobertura 60% → systemType:'hybrid' (viola RD-1 ampliado: primero ampliar paneles)\n  ✗ off-grid → wantsExcedentes:true (viola RD-2a)\n  ✗ on-grid cobertura 13% → wantsExcedentes:true (viola RD-2b: no hay excedentes)\n  ✗ availableArea: 60 → 50 (viola RD-3, reducir)\n  ✗ on-grid → battQty:N (viola RD-4, no hay baterías en on-grid)\n  ✗ on-grid → autonomyDays:2 (viola RD-4, autonomyDays solo off-grid)\n  ✗ off-grid → backupHours:8 (viola RD-4, backupHours solo hybrid)\n  ✗ trifasico → bifasico (viola RD-5, no se baja)\n  ✗ kWp 3, busVoltage 24 → 12 (viola RD-6, no se baja)\n  ✗ kWp 8, busVoltage 24 → 48 ✓ (válido — kWp>5 exige 48 V)\n  ✗ acometida actual 'bifasico' → bifasico (viola RD-7, mismo valor)\n  ✗ monthlyKwh: 500 → 600 (viola RD-8, no se modifica)\n\n- 'label' ≤60 chars, 'reason' ≤140 chars y debe citar el dato del payload que justifica el cambio.\n- NO inventes IDs de catálogo (panel/inversor/batería); el frontend NO los aplica.\n- Trabaja solo con los datos del payload.`;

function extractJson(text) {
  if (!text) return null;
  const m = text.match(/\{[\s\S]*\}/);
  if (!m) return null;
  try { return JSON.parse(m[0]); } catch (_) { return null; }
}

async function callGroq() {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: {
      'authorization': `Bearer ${GROQ}`,
      'content-type': 'application/json',
    },
    body: {
      model: 'llama-3.3-70b-versatile',
      max_tokens: 1500,
      temperature: 0.2,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: userPrompt },
      ],
    },
    json: true,
  });
  const text = r?.choices?.[0]?.message?.content || '';
  const usage = r?.usage || {};
  return { parsed: extractJson(text), provider: 'groq-llama-3.3-70b', tokens: { in: usage.prompt_tokens || 0, out: usage.completion_tokens || 0 }, raw: text };
}

async function callGemini() {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${encodeURIComponent(GEMINI)}`,
    headers: { 'content-type': 'application/json' },
    body: {
      systemInstruction: { parts: [{ text: system }] },
      contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
      generationConfig: { temperature: 0.2, maxOutputTokens: 1500, responseMimeType: 'application/json' },
    },
    json: true,
  });
  const text = (r?.candidates?.[0]?.content?.parts || []).map(p => p.text || '').join('\n').trim();
  const usage = r?.usageMetadata || {};
  return { parsed: extractJson(text), provider: 'gemini-2.0-flash', tokens: { in: usage.promptTokenCount || 0, out: usage.candidatesTokenCount || 0 }, raw: text };
}

async function callClaude() {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': CLAUDE,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json',
    },
    body: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 1500,
      system,
      messages: [{ role: 'user', content: userPrompt }],
    },
    json: true,
  });
  const text = (r.content || []).map(c => c.text || '').join('\n').trim();
  const usage = r.usage || {};
  return { parsed: extractJson(text), provider: 'claude-haiku-4-5', tokens: { in: usage.input_tokens || 0, out: usage.output_tokens || 0 }, raw: text };
}

const ladder = [];
if (GROQ)   ladder.push({ name: 'groq',   fn: callGroq.bind(this) });
if (GEMINI) ladder.push({ name: 'gemini', fn: callGemini.bind(this) });
if (CLAUDE) ladder.push({ name: 'claude', fn: callClaude.bind(this) });

const attempts = [];
let result = null;
let parsed = null;
for (const step of ladder) {
  try {
    const out = await step.fn();
    if (out && out.parsed) { result = out; parsed = out.parsed; break; }
    attempts.push({ provider: step.name, error: 'invalid_json', raw: (out?.raw || '').slice(0, 200) });
  } catch (e) {
    attempts.push({ provider: step.name, error: (e && e.message) ? e.message.slice(0, 200) : 'unknown' });
  }
}

if (!result) {
  return [{ json: { ok: false, reason: 'all_providers_failed', attempts } }];
}

// parsed already assigned in the cascade loop above (hoisted to prevent TDZ).
const rawActions = Array.isArray(parsed.actions) ? parsed.actions : [];
// monthlyKwh y IDs de catálogo NO son aplicables (RD-8). Los demás siguen el dominio del schema.
const allowedFields = new Set(['systemType','battQty','busVoltage','backupHours','autonomyDays','criticalPct','acometida','availableArea','wantsExcedentes']);

// Reglas duras de coherencia (servidor) — descartan actions inválidas aunque el modelo las devuelva.
const currentSysType = payload?.systemType;
const currentAcometida = payload?.acometida;
const currentBusVoltage = Number(payload?.busVoltage || 0);
const currentArea = Number(payload?.roof?.availableM2 || payload?.availableArea || 0) || null;
const currentWantsExcedentes = payload?.wantsExcedentes === true;
const monthlyKwh = Number(payload?.monthlyKwh || 0);
const monthlyProdKwh = Number(payload?.result?.monthlyProdKwh || 0);
const kwp = Number(payload?.result?.kwp || 0);
const coveragePct = monthlyKwh > 0 ? (monthlyProdKwh / monthlyKwh) * 100 : 0;
const hasSurplus = monthlyKwh > 0 && monthlyProdKwh > monthlyKwh;
const getCurrent = (field) => {
  if (field === 'availableArea') return currentArea;
  if (field === 'busVoltage') return currentBusVoltage;
  if (field === 'wantsExcedentes') return currentWantsExcedentes;
  if (field === 'acometida') return currentAcometida;
  if (field === 'systemType') return currentSysType;
  return payload?.[field] ?? payload?.backup?.[field] ?? null;
};
const acomRank = { monofasico: 1, bifasico: 2, trifasico: 3 };
const sanitizeAction = (a) => {
  if (!a || typeof a !== 'object' || !allowedFields.has(a.field)) return null;

  // RD-1: systemType — nunca cambiar desde off-grid; nunca on-grid undersized → hybrid.
  if (a.field === 'systemType') {
    if (currentSysType === 'off-grid') return null;
    if (currentSysType === 'on-grid' && a.value === 'hybrid' && coveragePct < 100) return null;
  }

  // RD-2: wantsExcedentes — solo si on-grid/hybrid Y hay excedentes reales.
  if (a.field === 'wantsExcedentes' && a.value === true) {
    if (currentSysType === 'off-grid') return null;
    if (!hasSurplus) return null;
  }

  // RD-3: availableArea — el usuario declara el área (realidad física), no se optimiza.
  if (a.field === 'availableArea') {
    const proposed = Number(a.value);
    if (!Number.isFinite(proposed) || proposed <= 0) return null;
    // Si el usuario YA declaró un área, ningún valor propuesto es válido.
    if (currentArea && currentArea > 0) return null;
    if (proposed > 5000) return null; // valor irreal
  }

  // RD-4: dominio por systemType.
  if (['battQty','busVoltage'].includes(a.field) && currentSysType === 'on-grid') return null;
  if (['backupHours','criticalPct'].includes(a.field) && currentSysType !== 'hybrid') return null;
  if (a.field === 'autonomyDays' && currentSysType !== 'off-grid') return null;

  // RD-5: acometida — solo escala según potencia, nunca baja.
  if (a.field === 'acometida') {
    const proposed = a.value;
    const cur = currentAcometida;
    if (!acomRank[proposed]) return null;
    if (cur && acomRank[proposed] < acomRank[cur]) return null; // no baja
    if (proposed === 'trifasico' && kwp > 0 && kwp < 10) return null; // solo si la potencia lo exige
    if (proposed === 'monofasico' && currentSysType !== 'off-grid') return null; // residencial mínimo bifasico
  }

  // RD-6: busVoltage — solo subir según potencia.
  if (a.field === 'busVoltage') {
    const proposed = Number(a.value);
    if (![12,24,48].includes(proposed)) return null;
    if (currentBusVoltage && proposed < currentBusVoltage) return null; // no baja
    if (proposed === 12 && kwp >= 2) return null;
    if (proposed === 24 && kwp > 5) return null;
  }

  // RD-7: no proponer mismo valor.
  const cur = getCurrent(a.field);
  if (cur !== null && cur !== undefined) {
    const propStr = JSON.stringify(a.value);
    const curStr = JSON.stringify(cur);
    if (propStr === curStr) return null;
  }

  return { field: String(a.field), value: a.value, label: String(a.label || '').slice(0, 80), reason: String(a.reason || '').slice(0, 200) };
};
const actions = rawActions.map(sanitizeAction).filter(Boolean);

// Guardrail server-side para suggestions: si el usuario YA marcó wantsExcedentes:true,
// descarta sugerencias que re-propongan AGPE / inscripción / venta de excedentes. RD-2
// del prompt lo prohíbe pero Groq llama-3.3 a veces lo ignora con prompts largos.
// Patrón: mención de AGPE/inscripción/venta-excedentes Y verbo de acción (considerar/
// evaluar/inscribir/vender). No filtra menciones contextuales sin proponer hacer algo.
// Numeric guardrail: si el modelo escribió un % de cobertura distinto al de facts,
// reemplazarlo. Patrón visto: "cobertura del 120%" cuando facts.coberturaPct=371.
// Solo opera cuando facts está disponible (cobertura >= 0).
function fixCoverageMentions(text, facts) {
  if (typeof text !== 'string' || !facts || facts.coberturaPct == null) return text;
  const real = Math.round(facts.coberturaPct);
  // Busca "cobertura" o "coverage" seguido (cerca) de un número con %.
  // Ej: "cobertura del 120%", "cobertura es de 28%", "una cobertura de 50 %".
  return text.replace(
    /(cobertur[ao]s+(?:del?|es|de|es del?|alcanza el?|llega al?)?s*)(\d{1,4})\s*%/gi,
    (match, prefix, num) => {
      const n = parseInt(num, 10);
      // Si está dentro de ±5% del valor real, no tocar (puede ser redondeo).
      if (Math.abs(n - real) <= 5) return match;
      return prefix + real + '%';
    }
  );
}
const fixCovList = (arr) => Array.isArray(arr)
  ? arr.map(s => typeof s === 'string' ? fixCoverageMentions(s, payload.facts) : s)
  : arr;
parsed.summary = fixCoverageMentions(parsed.summary || '', payload.facts);
parsed.findings = fixCovList(parsed.findings);
parsed.warnings = fixCovList(parsed.warnings);
// suggestions se procesa abajo en la asignación a 'suggestions' const.

const rawSuggestions = Array.isArray(parsed.suggestions) ? parsed.suggestions : [];
const isAgpeReSuggestion = (s) => {
  if (typeof s !== 'string') return false;
  const t = s.toLowerCase();
  const mentionsAgpe = /agpe|inscrib|vender (excedentes|energ[ií]a)|venta de excedentes|programa de excedentes/.test(t);
  if (!mentionsAgpe) return false;
  return /considerar|evaluar|inscrib|vender|venta|implementar|investigar/.test(t);
};
const filteredSuggestions = (payload?.wantsExcedentes === true)
  ? rawSuggestions.filter(s => !isAgpeReSuggestion(s))
  : rawSuggestions;
const suggestions = fixCovList(filteredSuggestions);

return [{ json: {
  summary: parsed.summary || '',
  findings: Array.isArray(parsed.findings) ? parsed.findings : [],
  warnings: Array.isArray(parsed.warnings) ? parsed.warnings : [],
  suggestions,
  actions,
  provider: result.provider,
  tokens: result.tokens,
  attempts,
} }];
